<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'
import { ElMessage } from 'element-plus'
import { orderApi, type Order } from '@/api/services'
const active = ref('ALL'); const orders = ref<Order[]>([]); const loading = ref(true); const labels: Record<string, string> = { ALL: '全部', PENDING_PAYMENT: '待付款', PAID: '待发货', SHIPPED: '待收货', COMPLETED: '已完成', CANCELED: '已取消' }; const displayed = computed(() => active.value === 'ALL' ? orders.value : orders.value.filter((item) => item.status === active.value)); const price = (value: number) => value.toFixed(2)
const load = async () => { loading.value = true; try { orders.value = (await orderApi.list({ page: 1, size: 20 })).items } finally { loading.value = false } }; const confirm = async (orderNo: string) => { await orderApi.confirm(orderNo); ElMessage.success('已确认收货'); load() }; onMounted(load)
</script>
<template><div class="shell page personal-layout"><aside class="personal-nav"><h3>个人中心</h3><RouterLink to="/profile">个人资料</RouterLink><RouterLink to="/orders" class="selected">我的订单</RouterLink><a>收货地址</a><a>账户安全</a></aside><section class="orders-content"><h1>我的订单</h1><el-tabs v-model="active"><el-tab-pane v-for="(label, value) in labels" :key="value" :label="label" :name="value" /></el-tabs><el-skeleton :loading="loading" animated :rows="8"><template #default><article v-for="order in displayed" :key="order.orderNo" class="order-card"><div class="order-meta"><span>{{ order.createdAt || '订单创建成功' }}</span><b>订单号：{{ order.orderNo }}</b><em>{{ labels[order.status] || order.status }}</em></div><div v-for="item in order.items" :key="item.skuId" class="order-product"><img :src="item.mainImageUrl || 'https://placehold.co/200x200/eaf3ff/1677ff?text=DingDong'" :alt="item.productTitle" /><div><b>{{ item.productTitle }}</b><p>{{ item.specJson }}</p></div><span>¥{{ price(item.unitPrice) }} × {{ item.quantity }}</span><strong>¥{{ price(item.totalAmount) }}</strong><el-button v-if="order.status === 'PENDING_PAYMENT'" type="primary" @click="$router.push({ path: '/payment', query: { orderNo: order.orderNo, amount: order.totalAmount } })">立即支付</el-button><el-button v-else-if="order.status === 'SHIPPED'" type="primary" plain @click="confirm(order.orderNo)">确认收货</el-button></div></article><el-empty v-if="!displayed.length" description="暂无订单" /></template></el-skeleton></section></div></template>
